+      status.textContent = `${currentCols}\u00d7${currentRows} \u2014 stopped (${totalFrames} frames)`;
+      jsonl({ event: "quit", total_frames: totalFrames, ts: Date.now() });
+      runner.destroy();
+    }
+  } catch (e) {
+    const errorText = e && typeof e === "object" && "stack" in e ? String(e.stack) : String(e);
+    jsonl({ event: "runtime_error", error: errorText, ts: Date.now() });
+    showError(`Runtime error in frame loop:\n${errorText}`);
+    try {
+      runner.destroy();
+    } catch (_) {}
   }
 }
